{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { size: A4 landscape; margin: 10mm 12mm 8mm 12mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 8.5pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 100%; margin: 0; padding: 0; }

  /* HEADER */
  .hotel-logo { max-height: 52px; max-width: 95px; }
  .logo-box { display: inline-block; width: 44px; height: 44px; background: #1a1a2e; color: #fff; font-size: 15pt; font-weight: 700; text-align: center; line-height: 44px; border-radius: 5px; }
  .hotel-name { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 12pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 12px 0 14px; }

  /* PILLS */
  .pill { display: inline-block; padding: 2px 9px; border-radius: 10px; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; margin-right: 5px; border: 1px solid #d1d5db; background: #f9fafb; color: #374151; }
  .pills-row { margin-bottom: 12px; }

  /* SECTION TITLE */
  .section-title { font-size: 7.5pt; font-weight: 700; color: #1a1a2e; text-transform: uppercase; letter-spacing: 0.6px; background: #f1f3f8; border-left: 3px solid #1a1a2e; border-bottom: 1px solid #d1d5db; padding: 5px 9px; margin-top: 14px; margin-bottom: 8px; }

  /* INFO TABLE */
  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td { padding: 4px 8px; font-size: 8.5pt; border-bottom: 1px solid #f1f5f9; vertical-align: middle; white-space: nowrap; }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 14%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 19%; color: #1a1a2e; font-weight: 400; }

  /* STATS */
  .stats-table { width: 100%; border-collapse: collapse; margin-bottom: 12px; }
  .stats-table td { border: 1px solid #e5e7eb; padding: 5px 8px; text-align: center; }
  .s-label { font-size: 6.5pt; color: #9ca3af; display: block; text-transform: uppercase; letter-spacing: 0.4px; }
  .s-value { font-size: 11pt; font-weight: 700; color: #1a1a2e; display: block; margin-top: 2px; }
  .s-value.green { color: #15803d; }
  .s-value.red { color: #dc2626; }
  .s-value.blue { color: #1d4ed8; }
  .s-value.amber { color: #d97706; }

  /* DATA TABLE */
  .data-table { width: 100%; border-collapse: collapse; font-size: 7.5pt; margin-bottom: 4px; }
  .data-table thead tr { background: #f1f3f8; color: #1a1a2e; border-bottom: 2px solid #1a1a2e; }
  .data-table thead th { padding: 5px 5px; text-align: left; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.3px; white-space: nowrap; border-bottom: 2px solid #1a1a2e; }
  .data-table thead th.num { text-align: right; }
  .data-table thead th.ctr { text-align: center; }
  .data-table tbody tr:nth-child(even) { background: #f9fafb; }
  .data-table tbody td { padding: 5px 5px; border-bottom: 1px solid #f1f5f9; color: #374151; vertical-align: middle; }
  .data-table tbody td.num { text-align: right; font-variant-numeric: tabular-nums; }
  .data-table tbody td.ctr { text-align: center; }
  .data-table tfoot tr { border-top: 2px solid #1a1a2e; background: #f1f3f8; color: #1a1a2e; }
  .data-table tfoot td { padding: 6px 5px; font-weight: 700; color: #1a1a2e; font-size: 8pt; }
  .data-table tfoot td.num { text-align: right; }

  /* STATUS PILLS */
  .badge { display: inline-block; padding: 1px 6px; border-radius: 8px; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; white-space: nowrap; }
  .badge-occupied    { background: #dcfce7; color: #166534; border: 1px solid #bbf7d0; }
  .badge-vacant-clean { background: #dbeafe; color: #1d4ed8; border: 1px solid #bfdbfe; }
  .badge-vacant-dirty { background: #f3f4f6; color: #4b5563; border: 1px solid #e5e7eb; }
  .badge-overdue     { background: #fee2e2; color: #b91c1c; border: 1px solid #fecaca; }
  .badge-maintenance { background: #ffedd5; color: #c2410c; border: 1px solid #fed7aa; }

  .paid-text { color: #15803d; font-weight: 700; }
  .part-text { color: #d97706; font-weight: 700; }
  .unpaid-text { color: #dc2626; font-weight: 700; }

  /* FOOTER */
  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 14px 0 8px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 14px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Daily Occupancy Report</div>
        <div class="doc-subtitle">Room Status &amp; Revenue</div>
        <div class="doc-ref">
          <strong>Period:</strong> {{ filters.date_from }} &ndash; {{ filters.date_to }}<br>
          <strong>Generated:</strong> {{ generated_at }}<br>
          <strong>Prepared By:</strong> {{ prepared_by }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- PILLS -->
  <div class="pills-row">
    {% if filters.date_from == filters.date_to %}
      <span class="pill">{{ filters.date_from }}</span>
    {% else %}
      <span class="pill">{{ filters.date_from }} &ndash; {{ filters.date_to }}</span>
    {% endif %}
    {% if applied_filters.status %}<span class="pill">{{ applied_filters.status }}</span>{% endif %}
    {% if applied_filters.floor %}<span class="pill">{{ applied_filters.floor }}</span>{% endif %}
    {% if applied_filters.payment %}<span class="pill">{{ applied_filters.payment }}</span>{% endif %}
    {% if applied_filters.overdue_only == 'Yes' %}<span class="pill">Overdue Only</span>{% endif %}
  </div>

  <!-- SUMMARY -->
  <div class="section-title">Summary</div>
  <table class="stats-table" cellpadding="0" cellspacing="0">
    <tr>
      <td>
        <span class="s-label">Occupancy Rate</span>
        <span class="s-value">{{ stats.occupancyRate }}%</span>
      </td>
      <td>
        <span class="s-label">Total Rooms</span>
        <span class="s-value">{{ stats.totalRooms }}</span>
      </td>
      <td>
        <span class="s-label">Occupied</span>
        <span class="s-value green">{{ stats.occupiedRooms }}</span>
      </td>
      <td>
        <span class="s-label">Vacant</span>
        <span class="s-value blue">{{ stats.vacantRooms }}</span>
      </td>
      <td>
        <span class="s-label">Arrivals</span>
        <span class="s-value">{{ stats.arrivals }}</span>
      </td>
      <td>
        <span class="s-label">Departures</span>
        <span class="s-value">{{ stats.departures }}</span>
      </td>
      <td>
        <span class="s-label">Overdue Check-Out</span>
        <span class="s-value red">{{ stats.overdueCheckOut }}</span>
      </td>
      <td>
        <span class="s-label">Room Revenue</span>
        <span class="s-value" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(stats.roomRevenue | float) }}</span>
      </td>
      <td>
        <span class="s-label">POS Revenue</span>
        <span class="s-value" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(stats.posRevenue | float) }}</span>
      </td>
      <td>
        <span class="s-label">Total Collected</span>
        <span class="s-value green" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(stats.totalCollected | float) }}</span>
      </td>
      <td>
        <span class="s-label">Outstanding</span>
        <span class="s-value red" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(stats.outstanding | float) }}</span>
      </td>
    </tr>
  </table>

  <!-- ROOM OCCUPANCY TABLE -->
  <div class="section-title">Room Occupancy Details &mdash; {{ rows | length }} record(s)</div>
  {% if rows %}
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th class="ctr">#</th>
        <th>Check-In ID</th>
        <th>Room</th>
        <th>Type</th>
        <th>Status</th>
        <th>Guest Name</th>
        <th>Check-In</th>
        <th>Check-Out</th>
        <th class="ctr">Nights</th>
        <th class="num">Rate</th>
        <th class="num">Discount</th>
        <th class="num">Amount</th>
        <th class="num">Paid</th>
        <th class="num">Balance</th>
        <th>Payment</th>
      </tr>
    </thead>
    <tbody>
      {% for row in rows %}
      <tr>
        <td class="ctr" style="color:#9ca3af;">{{ loop.index }}</td>
        <td style="font-size:7pt;color:#6b7280;">{{ row.checkin_id or '&mdash;' }}</td>
        <td style="font-weight:700;color:#1a1a2e;">{{ row.room_number }}</td>
        <td style="color:#6b7280;">{{ row.room_type or '&mdash;' }}</td>
        <td>
          {% set s = row.status or '' %}
          {% if s == 'Occupied' %}
            <span class="badge badge-occupied">Occupied</span>
          {% elif s == 'Vacant Clean' %}
            <span class="badge badge-vacant-clean">Vacant Clean</span>
          {% elif s == 'Vacant Dirty' %}
            <span class="badge badge-vacant-dirty">Vacant Dirty</span>
          {% elif s == 'Overdue Check-Out' %}
            <span class="badge badge-overdue">Overdue</span>
          {% elif s == 'Maintenance' %}
            <span class="badge badge-maintenance">Maintenance</span>
          {% else %}
            <span class="badge badge-vacant-dirty">{{ s or '&mdash;' }}</span>
          {% endif %}
        </td>
        <td style="font-weight:600;">{{ row.guest or '&mdash;' }}</td>
        <td style="white-space:nowrap;font-size:7pt;">{{ row.checkin or '&mdash;' }}</td>
        <td style="white-space:nowrap;font-size:7pt;">{{ row.checkout or '&mdash;' }}</td>
        <td class="ctr">{{ row.nights or 0 }}</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(row.rate | float) }}</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(row.discount | float) }}</td>
        <td class="num" style="font-weight:600;">&#x20a6;{{ "{:,.0f}".format(row.amount | float) }}</td>
        <td class="num paid-text">&#x20a6;{{ "{:,.0f}".format(row.paid_amount | float) }}</td>
        <td class="num {% if row.outstanding | float > 0 %}unpaid-text{% else %}paid-text{% endif %}">
          &#x20a6;{{ "{:,.0f}".format(row.outstanding | float) }}
        </td>
        <td>
          {% set ps = (row.payment_status or '') %}
          {% if ps == 'Paid' %}
            <span style="color:#15803d;font-weight:700;">Paid</span>
          {% elif ps == 'Part Payment' %}
            <span style="color:#d97706;font-weight:700;">Part</span>
          {% elif ps == 'Unpaid' %}
            <span style="color:#dc2626;font-weight:700;">Unpaid</span>
          {% else %}
            {{ ps or '&mdash;' }}
          {% endif %}
        </td>
      </tr>
      {% endfor %}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="9" style="text-align:right;text-transform:uppercase;letter-spacing:0.5px;">Grand Total</td>
        <td class="num">{{ totals.nights }}</td>
        <td></td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(totals.discount | float) }}</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(totals.amount | float) }}</td>
        <td class="num" style="color:#86efac;">&#x20a6;{{ "{:,.0f}".format(totals.paid_amount | float) }}</td>
        <td class="num" style="color:#fca5a5;">&#x20a6;{{ "{:,.0f}".format(totals.outstanding | float) }}</td>
        <td></td>
      </tr>
    </tfoot>
  </table>
  {% else %}
  <p style="padding:16px;text-align:center;color:#9ca3af;font-size:8.5pt;border:1px dashed #e5e7eb;">No occupancy records found for this period.</p>
  {% endif %}

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This report is generated by the {{ company }} Property Management System.<br>
          Front Office Note: Overdue check-outs and unpaid balances should be followed up immediately.<br>
          <strong style="color:#374151;">Period: {{ filters.date_from }} to {{ filters.date_to }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
